import numpy as np
import random
import copy

# ── Gradient Checker ──────────────────────────────────────────────
def gradcheck_naive(f, x, h=1e-4, tol=1e-5):
    """
    Reproducible numerical gradient check using central difference.
    f: function that takes x and returns (cost, gradient)
    x: numpy array — point at which to check gradient
    """
    # Save random state for reproducibility
    rndstate = random.getstate()
    random.setstate(rndstate)

    fx, grad = f(x)  # analytical gradient

    it = np.nditer(x, flags=['multi_index'], op_flags=['readwrite'])
    passed = True

    while not it.finished:
        ix = it.multi_index

        # f(x + h)
        xp = copy.deepcopy(x)
        xp[ix] += h
        random.setstate(rndstate)
        fxp, _ = f(xp)

        # f(x - h)
        xn = copy.deepcopy(x)
        xn[ix] -= h
        random.setstate(rndstate)
        fxn, _ = f(xn)

        numgrad = (fxp - fxn) / (2 * h)

        # Relative difference
        reldiff = abs(numgrad - grad[ix]) / max(1, abs(numgrad), abs(grad[ix]))

        if reldiff > tol:
            print(f"❌ Gradient check FAILED at index {ix}")
            print(f"   Analytical : {grad[ix]:.6f}")
            print(f"   Numerical  : {numgrad:.6f}")
            print(f"   Rel. diff  : {reldiff:.2e}")
            passed = False

        it.iternext()

    if passed:
        print("✅ Gradient check PASSED!")
    return passed


# ── Test Case: SVM / Logistic Regression cost ─────────────────────
np.random.seed(42)
random.seed(42)

N = 20
X = np.random.randn(N, 3)
Y = np.where(np.random.rand(N) > 0.5, 1, -1).astype(float)

def svm_cost_and_grad(w, C=1.0):
    scores = X.dot(w)
    margins = np.maximum(0, 1 - Y * scores)
    cost = 0.5 * np.dot(w, w) + C * np.sum(margins)
    # Gradient
    mask = (Y * scores) < 1
    grad = w - C * X[mask].T.dot(Y[mask])
    return cost, grad

# Wrap for checker (single-argument function)
f = lambda w: svm_cost_and_grad(w)

w0 = np.random.randn(3)
gradcheck_naive(f, w0)

